from Crypto.Util.number import long_to_bytes
from math import gcd


e1=65537
e2=65539



def egcd(a, b):
    if b == 0:
        return a, 1, 0
    g, x1, y1 = egcd(b, a % b)
    return g, y1, x1 - (a // b) * y1

